contracts/zombiehelper.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./zombiefeeding.sol";

contract ZombieHelper is ZombieFeeding {

    uint levelUpFee = 0.001 ether;

    modifier aboveLevel(uint32 _level, uint256 _zombieId) {
        zombies[_zombieId].level >= _level;
        _;
    }

    function withdraw() external payable {
        address payable _owner = payable((owner()));
        _owner.transfer(address(this).balance);
        // 简介写法：
        // payable(owner()).transfer(address(this).balance);
    }

    function setLevelUpFee(uint _fee) external onlyOwner {
        levelUpFee = _fee;
    }

    function levelUp(uint _zombieId) external payable {
        require(msg.sender == zombieToOwner[_zombieId]);
        require(msg.value == levelUpFee);
        zombies[_zombieId].level++;
    }

    function changeName(uint _zombieId, string calldata _newName) external aboveLevel(2, _zombieId) {
        require(zombieToOwner[_zombieId] == msg.sender);
        zombies[_zombieId].name = _newName;
    }
    function changeDna(uint _zombieId, uint _newDna) external aboveLevel(20, _zombieId) {
        require(zombieToOwner[_zombieId] == msg.sender);
        zombies[_zombieId].dna = _newDna;
    }

    function getZombieByOwner(address _owner) external view returns (uint[] memory) {
        uint[] memory result = new uint[](ownerZombieCount[_owner]);
        uint counter = 0;
        for (uint256 _id = 0; _id < zombies.length; _id++) {
            if (zombieToOwner[_id] == _owner) {
                result[counter] = _id;
                counter++;
            }
        }
        return result;
    }
}

contracts/zombiefeeding.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./zombiefactory.sol";

abstract contract KittyInterface {
    function getKitty(uint256 _id) external view virtual returns (
        bool isGestating,
        bool isReady,
        uint256 cooldownIndex,
        uint256 nextActionAt,
        uint256 siringWithId,
        uint256 birthTime,
        uint256 matronId,
        uint256 sireId,
        uint256 generation,
        uint256 genes
        );
}

contract ZombieFeeding is ZombieFactory {

    KittyInterface kittyContract;

    function setKittyContractAddress(address _address) external onlyOwner {
        kittyContract = KittyInterface(_address);
    }

    function _triggerCooldown(Zombie storage _zombie) private {
        _zombie.readyTime = uint32(block.timestamp + cooldownTime);
    }

    function _isReady(Zombie storage _zombie) internal view returns(bool) {
        return _zombie.readyTime <= block.timestamp;
    }


    function feeAndMultiply(uint256 _zombieId, uint256 _targetDna, string memory _species) internal {
        require(zombieToOwner[_zombieId] == msg.sender);
        Zombie storage myZombie = zombies[_zombieId];
        _targetDna = _targetDna % dnaModulus;
        require(_isReady(myZombie));
        uint256 newDna = (_targetDna + myZombie.dna) / 2;
        if(keccak256(abi.encodePacked(_species)) == keccak256(abi.encodePacked("kitty"))) {
            newDna = newDna - newDna % 100 + 99;
        }
        _createZombie("NoName", newDna);
        _triggerCooldown(myZombie);
    }

    function feeOnKitty(uint256 _zombieId, uint256 _kittyId) public {
        (,,,,,,,,,uint256 kittyDna) = kittyContract.getKitty(_kittyId);
        feeAndMultiply(_zombieId, kittyDna, "kitty");
    }

}

